import{_ as a,c as e,o as m,b as t}from"./app.81e64653.js";const y='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 10-11","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 10-11","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 3.","tags":"vim-3","date":"2021-02-04T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/3/10-11/index.md"}',r={},o=t('<p>:: stanza 3.10</p><div class="sans"><p>\u090F\u0935\u0902\u0935\u093F\u0927\u0938\u094D\u092F\u093E\u0938\u094D\u092F \u091C\u0917\u0928\u094D\u0928\u093E\u091F\u094D\u092F\u0928\u0930\u094D\u0924\u0915\u0938\u094D\u092F \u092D\u0942\u092E\u093F\u0915\u093E\u0917\u094D\u0930\u0939\u0923\u092A\u0926\u092C\u0928\u094D\u0927\u0938\u094D\u0925\u093E\u0928\u0930\u0919\u094D\u0917\u092E\u093E\u0939\u2014</p><blockquote><p><strong>\u0930\u0919\u094D\u0917\u094B\u093D\u0928\u094D\u0924\u0930\u093E\u0924\u094D\u092E\u093E\u0965\u0967\u0966\u0965</strong></p></blockquote><p>\u0930\u091C\u094D\u092F\u0924\u0947\u093D\u0938\u094D\u092E\u093F\u091E\u094D\u091C\u0917\u0928\u094D\u0928\u093E\u091F\u094D\u092F\u0915\u094D\u0930\u0940\u0921\u093E\u092A\u094D\u0930\u0926\u0930\u094D\u0936\u0928\u093E\u0936\u092F\u0947\u0928\u093E\u0924\u094D\u092E\u0928\u0947\u0924\u093F \u0930\u0919\u094D\u0917\u0938\u094D\u0924\u0924\u094D\u0924\u0926\u094D\u092D\u0942\u092E\u093F\u0915\u093E\u0917\u094D\u0930\u0939\u0923\u0938\u094D\u0925\u093E\u0928\u092E\u0928\u094D\u0924\u0930\u093E\u0924\u094D\u092E\u093E \u0938\u0919\u094D\u0915\u094B\u091A\u093E\u0935\u092D\u093E\u0938\u0938\u0924\u0924\u094D\u0924\u094D\u0935\u0903 \u0936\u0942\u0928\u094D\u092F\u092A\u094D\u0930\u0927\u093E\u0928\u0903 \u092A\u094D\u0930\u093E\u0923\u092A\u094D\u0930\u0927\u093E\u0928\u094B \u0935\u093E \u092A\u0941\u0930\u094D\u092F\u0937\u094D\u091F\u0915\u0930\u0942\u092A\u094B \u0926\u0947\u0939\u093E\u092A\u0947\u0915\u094D\u0937\u092F\u093E\u0928\u094D\u0924\u0930\u094B \u091C\u0940\u0935\u0903\u0964 \u0924\u0924\u094D\u0930 \u0939\u094D\u092F\u092F\u0902 \u0915\u0943\u0924\u092A\u0926\u0903 \u0938\u094D\u0935\u0915\u0930\u0923\u092A\u0930\u093F\u0938\u094D\u092A\u0928\u094D\u0926\u0915\u094D\u0930\u092E\u0947\u0923 \u091C\u0917\u0928\u094D\u0928\u093E\u091F\u094D\u092F\u092E\u093E\u092D\u093E\u0938\u092F\u0924\u093F\u0964 \u0909\u0915\u094D\u0924\u0902 \u091A \u0936\u094D\u0930\u0940\u0938\u094D\u0935\u091A\u094D\u091B\u0928\u094D\u0926\u0947</p><blockquote><p>\u092A\u0941\u0930\u094D\u092F\u0937\u094D\u091F\u0915\u0938\u092E\u093E\u092F\u094B\u0917\u093E\u0924\u094D\u092A\u0930\u094D\u092F\u091F\u0947\u0924\u094D\u0938\u0930\u094D\u0935\u092F\u094B\u0928\u093F\u0937\u0941\u0964<br> \u0905\u0928\u094D\u0924\u0930\u093E\u0924\u094D\u092E\u093E \u0938 \u0935\u093F\u091C\u094D\u091E\u0947\u092F\u0903...\u0965</p></blockquote><p>\u0907\u0924\u093F\u0965\u0967\u0966\u0965</p></div><hr><div class="trans"><p>Eva\u1E41vidhasy\u0101sya jagann\u0101\u1E6Dyanartakasya bh\u016Bmik\u0101graha\u1E47apadabandhasth\u0101nara\u1E45gam\u0101ha\u2014</p><blockquote><p><strong>Ra\u1E45go&#39;ntar\u0101tm\u0101||10||</strong></p></blockquote><p>Rajyate&#39;smi\xF1jagann\u0101\u1E6Dyakr\u012B\u1E0D\u0101pradar\u015Ban\u0101\u015Bayen\u0101tmaneti ra\u1E45gastattadbh\u016Bmik\u0101graha\u1E47asth\u0101namantar\u0101tm\u0101 sa\u1E45koc\u0101vabh\u0101sasatattva\u1E25 \u015B\u016Bnyapradh\u0101na\u1E25 pr\u0101\u1E47apradh\u0101no v\u0101 purya\u1E63\u1E6Dakar\u016Bpo deh\u0101pek\u1E63ay\u0101ntaro j\u012Bva\u1E25| Tatra hyaya\u1E41 k\u1E5Btapada\u1E25 svakara\u1E47aparispandakrame\u1E47a jagann\u0101\u1E6Dyam\u0101bh\u0101sayati| Ukta\u1E41 ca \u015Br\u012Bsvacchande</p><blockquote><p>Purya\u1E63\u1E6Dakasam\u0101yog\u0101tparya\u1E6Detsarvayoni\u1E63u|<br> Antar\u0101tm\u0101 sa vij\xF1eya\u1E25...||</p></blockquote><p>iti||10||</p></div><hr><p>[\u0412 \u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0435\u043C \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0435, \u015Aiva] \u0433\u043E\u0432\u043E\u0440\u0438\u043B <em>(\u0101ha)</em> \u043E \u0441\u0446\u0435\u043D\u0435 <em>(ra\u1E45gam)</em>, \u0438\u043B\u0438 \u043C\u0435\u0441\u0442\u0435 <em>(sth\u0101na)</em>, [\u0433\u0434\u0435] \u044D\u0442\u043E\u0442 \u0432\u0438\u0434 <em>(eva\u1E41vidhasya asya)</em> \u0430\u043A\u0442\u0435\u0440\u0430 <em>(nartakasya)</em> \u0432 \u0442\u0430\u043D\u0446\u0435\u0432\u0430\u043B\u044C\u043D\u043E\u0439 \u0434\u0440\u0430\u043C\u0435 <em>(n\u0101\u1E6Dya)</em>, [\u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u043E\u0439] \u043C\u0438\u0440 <em>(jagat)</em>, \u043F\u0440\u043E\u0447\u043D\u043E \u0441\u0442\u0430\u0432\u0438\u0442 [\u0441\u0432\u043E\u0438] \u0441\u0442\u043E\u043F\u044B <em>(pada-bandha)</em> [\u0438] \u0438\u0433\u0440\u0430\u0435\u0442 <em>(graha\u1E47a)</em> [\u0441\u0432\u043E\u044E] \u0440\u043E\u043B\u044C <em>(bh\u016Bmik\u0101)</em>\u2014</p><blockquote><p><strong>\u0421\u0446\u0435\u043D\u043E\u0439 [\u044D\u0442\u043E\u043C\u0443 Nartaka, \u0438\u043B\u0438 \u0442\u0430\u043D\u0446\u0443\u044E\u0449\u0435\u043C\u0443 \u0430\u043A\u0442\u0435\u0440\u0443 \u0434\u043B\u044F \u0438\u0433\u0440\u044B --\u0441\u043C. 9<sup>\u044B\u0439</sup> \u0430\u0444\u043E\u0440\u0438\u0437\u043C--] <em>(ra\u1E45ga\u1E25)</em> [\u0441\u043B\u0443\u0436\u0438\u0442 \u0435\u0433\u043E] \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044F\u044F <em>(antar)</em> \u0434\u0443\u0448\u0430 <em>(\u0101tm\u0101)</em>, [\u0441\u043E\u0441\u0442\u043E\u044F\u0449\u0430\u044F \u0438\u0437 \u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0438 \u0442\u043E\u043D\u043A\u043E\u0433\u043E \u0442\u0435\u043B]||10||</strong></p></blockquote><p>Ra\u1E45ga, \u0438\u043B\u0438 \u0441\u0446\u0435\u043D\u0430 \u2014 \u044D\u0442\u043E (\u0442\u043E \u043C\u0435\u0441\u0442\u043E) <em>(iti ra\u1E45ga\u1E25)</em>, \u0433\u0434\u0435 <em>(asmin)</em> \u0421\u0430\u043C\u043E\u0441\u0442\u044C <em>(\u0101tman\u0101)</em> \u0432\u043E\u0441\u0445\u0438\u0449\u0430\u0435\u0442\u0441\u044F <em>(rajyate)</em> \u043D\u0430\u043C\u0435\u0440\u0435\u043D\u0438\u0435\u043C <em>(\u0101\u015Bayena)</em> \u0434\u0435\u043C\u043E\u043D\u0441\u0442\u0440\u0430\u0446\u0438\u0438 <em>(pradar\u015Bana)</em> \u0438\u0433\u0440\u044B <em>(kr\u012B\u1E0D\u0101)</em> \u0442\u0430\u043D\u0446\u0435\u0432\u0430\u043B\u044C\u043D\u043E\u0439 \u0434\u0440\u0430\u043C\u044B <em>(n\u0101\u1E6Dya)</em>, [\u0438\u0437\u0432\u0435\u0441\u0442\u043D\u043E\u0439 \u043A\u0430\u043A] \u043C\u0438\u0440 <em>(jagat)</em>. [\u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, ra\u1E45ga \u2014 \u044D\u0442\u043E] \u043C\u0435\u0441\u0442\u043E <em>(sth\u0101nam)</em>, [\u0433\u0434\u0435 \u0421\u0430\u043C\u043E\u0441\u0442\u044C] \u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442 <em>(graha\u1E47a)</em> \u0440\u0430\u0437\u043B\u0438\u0447\u043D\u044B\u0435 <em>(tad-tad)</em> \u0440\u043E\u043B\u0438 <em>(bh\u016Bmik\u0101)</em>. Antar\u0101tm\u0101 <em>(antar-\u0101tm\u0101)</em> [\u2014 \u044D\u0442\u043E] \u0434\u0443\u0448\u0430, \u0438\u043B\u0438 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E <em>(j\u012Bva\u1E25)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 <em>(antara\u1E25)</em> \u043F\u043E \u043E\u0442\u043D\u043E\u0448\u0435\u043D\u0438\u044E \u043A <em>(apek\u1E63ay\u0101)</em> [\u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u043C\u0443] \u0442\u0435\u043B\u0443 <em>(deha)</em>. [\u0422\u0430\u043A\u0430\u044F \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u044F\u044F \u0434\u0443\u0448\u0430] \u0438\u043C\u0435\u0435\u0442 \u0442\u043E\u043D\u043A\u043E\u0435 \u0442\u0435\u043B\u043E <em>(purya\u1E63\u1E6Daka)</em> \u0432 \u043A\u0430\u0447\u0435\u0441\u0442\u0432\u0435 \u0441\u0432\u043E\u0435\u0439 \u0444\u043E\u0440\u043C\u044B <em>(r\u016Bpa\u1E25)</em>, [\u0438] \u0435\u0435 \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(satattva\u1E25)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u043C <em>(sa\u1E45koca)</em> \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435\u043C <em>(avabh\u0101sa)</em>, \u0447\u044C\u044F \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0430\u044F \u0447\u0430\u0441\u0442\u044C <em>(pradh\u0101na\u1E25... pradh\u0101na\u1E25)</em> [\u2014 \u044D\u0442\u043E \u043B\u0438\u0431\u043E] \u043F\u0443\u0441\u0442\u043E\u0442\u0430 <em>(\u015B\u016Bnya)</em>, \u043B\u0438\u0431\u043E <em>(v\u0101)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F <em>(pr\u0101\u1E47a)</em><sup>1</sup>|</p><p>\u042D\u0442\u043E\u0442 [Nartaka] <em>(ayam)</em>, \u0447\u044C\u0438 \u0441\u0442\u043E\u043F\u044B \u043F\u0440\u043E\u0447\u043D\u043E \u0441\u0442\u043E\u044F\u0442 <em>(k\u1E5Bta-pada\u1E25)</em> \u043D\u0430 \u044D\u0442\u043E\u0439 [\u0441\u0446\u0435\u043D\u0435] <em>(tatra hi)</em>, \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442 <em>(\u0101bh\u0101sayati)</em> \u0442\u0430\u043D\u0446\u0435\u0432\u0430\u043B\u044C\u043D\u0443\u044E \u0434\u0440\u0430\u043C\u0443 <em>(n\u0101\u1E6Dyam)</em>, [\u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u0443\u044E] \u043C\u0438\u0440\u043E\u043C <em>(jagat)</em>, \u043F\u043E\u0441\u0440\u0435\u0434\u0441\u0442\u0432\u043E\u043C \u043F\u043E\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438 <em>(krame\u1E47a)</em> \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u0439 <em>(parispanda)</em> \u0441\u0432\u043E\u0438\u0445 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u0445 <em>(sva)</em> [\u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445] \u0447\u0443\u0432\u0441\u0442\u0432 <em>(kara\u1E47a)</em><sup>2</sup>|</p><p>[\u042D\u0442\u043E \u0431\u044B\u043B\u043E] \u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam ca)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Svacchandatantra <em>(\u015Br\u012B-svacchande)</em>:</p><blockquote><p>&quot;\u0412\u0445\u043E\u0434\u044F \u0432 \u043A\u043E\u043D\u0442\u0430\u043A\u0442 <em>(sam\u0101yog\u0101t)</em> \u0441 \u0442\u043E\u043D\u043A\u0438\u043C \u0442\u0435\u043B\u043E\u043C, \u0438\u043B\u0438 purya\u1E63\u1E6Daka <em>(purya\u1E63\u1E6Daka)</em>, \u043E\u043D <em>(sa\u1E25)</em> \u0431\u043B\u0443\u0436\u0434\u0430\u0435\u0442 <em>(parya\u1E6Det)</em> \u0432\u043E \u0432\u0441\u0435\u0445 \u0444\u043E\u0440\u043C\u0430\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F <em>(sarva-yoni\u1E63u)</em> [\u0438, \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E,] \u0438\u0437\u0432\u0435\u0441\u0442\u0435\u043D \u043A\u0430\u043A <em>(vij\xF1eya\u1E25)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0435 <em>(antar)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E, \u0438\u043B\u0438 \u0434\u0443\u0448\u0430 <em>(\u0101tm\u0101... iti)</em>...<sup>3</sup>&quot;||<br> [\u0421\u043C. X, 85 \u0432 Svacchandatantra]</p></blockquote><p>||10||</p><hr><ol><li><p>\u0422\u043E, \u0447\u0442\u043E \u0430\u0432\u0442\u043E\u0440 \u043D\u0430\u043C\u0435\u0440\u0435\u0432\u0430\u043B\u0441\u044F \u0441\u043A\u0430\u0437\u0430\u0442\u044C, \u043F\u0440\u043E\u0441\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0432 \u0442\u043E\u043C, \u0447\u0442\u043E \u043F\u0440\u0438\u0440\u043E\u0434\u0430 \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0439 \u0434\u0443\u0448\u0438 \u2014 \u044D\u0442\u043E \u043F\u0440\u0438\u0447\u0438\u043D\u043D\u043E\u0435 (\u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u0435) \u0442\u0435\u043B\u043E (\u043F\u0443\u0441\u0442\u043E\u0442\u0430 \u0438 \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u0430\u044F \u044D\u043D\u0435\u0440\u0433\u0438\u044F, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0442 \u0441\u043E\u0431\u043E\u0439 \u0441\u043E\u043A\u0440\u0430\u0449\u0435\u043D\u043D\u043E\u0435 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0435 \u015Aakti), \u043D\u043E \u0435\u0433\u043E \u0444\u043E\u0440\u043C\u0430 (\u043A\u0430\u043A \u043E\u0434\u0435\u0436\u0434\u0430) \u0435\u0441\u0442\u044C \u0442\u043E\u043D\u043A\u043E\u0435 \u0442\u0435\u043B\u043E, \u0438\u043B\u0438 purya\u1E63\u1E6Daka (\u0438\u043D\u0442\u0435\u043B\u043B\u0435\u043A\u0442, \u044D\u0433\u043E, \u0443\u043C \u0438 \u043F\u044F\u0442\u044C \u0442\u043E\u043D\u043A\u0438\u0445 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u044B\u0445 \u0422\u0430\u043D\u043C\u0430\u0442\u0440\u0430\u043C\u0438 (Tanm\u0101tra-s)). \u0412\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u0434\u043E\u0431\u0430\u0432\u0438\u043B \u0432 \u0441\u0432\u043E\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0433\u043E \u0430\u0444\u043E\u0440\u0438\u0437\u043C\u0430: &quot;\u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u043E\u0441\u0442\u043E\u0438\u0442 \u0438\u0437 \u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u0433\u043E \u0438 \u0442\u043E\u043D\u043A\u043E\u0433\u043E \u0442\u0435\u043B&quot;.</p></li><li><p>\u042D\u0442\u0438 \u0434\u0432\u0438\u0436\u0435\u043D\u0438\u044F \u0435\u0433\u043E \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0438\u0445 \u0447\u0443\u0432\u0441\u0442\u0432 \u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F \u0432\u0438\u0431\u0440\u0430\u0446\u0438\u044F\u043C\u0438 \u0415\u0441\u0442\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0439 Sv\u0101tantrya\u015Bakti \u0413\u043E\u0441\u043F\u043E\u0434\u0430 (\u0415\u0433\u043E \u0421\u0438\u043B\u044B \u0410\u0431\u0441\u043E\u043B\u044E\u0442\u043D\u043E\u0439 \u0421\u0432\u043E\u0431\u043E\u0434\u044B).</p></li><li><p>\u0422\u043E\u0447\u043A\u0438 \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0435\u043D\u0438\u044F \u043E\u0437\u043D\u0430\u0447\u0430\u044E\u0442 \u043E\u0441\u0442\u0430\u0432\u0448\u0443\u044E\u0441\u044F \u0447\u0430\u0441\u0442\u044C \u0441\u0442\u0440\u043E\u0444\u044B: &quot;\u0928\u093F\u092C\u0926\u094D\u0927\u0938\u094D\u0924\u0941 \u0936\u0941\u092D\u093E\u0936\u0941\u092D\u0948\u0903\u0964 &quot; - &quot;nibaddhastu \u015Bubh\u0101\u015Bubhai\u1E25|&quot; - &quot;\u0447\u0442\u043E \u0431\u0435\u0437\u0443\u0441\u043B\u043E\u0432\u043D\u043E \u0441\u0432\u044F\u0437\u0430\u043D\u043E \u0441 \u0445\u043E\u0440\u043E\u0448\u0438\u043C \u0438 \u043F\u043B\u043E\u0445\u0438\u043C [v\u0101san\u0101-s, \u0438\u043B\u0438 \u0442\u0435\u043D\u0434\u0435\u043D\u0446\u0438\u044F\u043C\u0438]&quot;. \u0422\u043E, \u0447\u0442\u043E \u0431\u044B\u043B\u043E \u0434\u043E\u0431\u0430\u0432\u043B\u0435\u043D\u043E \u043C\u043D\u043E\u0439 \u0432 \u043A\u0440\u0443\u0433\u043B\u044B\u0445 \u0441\u043A\u043E\u0431\u043A\u0430\u0445, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0441\u043E\u0433\u043B\u0430\u0441\u0443\u0435\u0442\u0441\u044F \u0441 \u0442\u0435\u043C, \u043A\u0430\u043A \u043C\u0443\u0434\u0440\u0435\u0446 K\u1E63emar\u0101ja \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u0432 \u0435\u0433\u043E Svacchandoddyota: &quot;\u0924\u0924\u094D\u0938\u092E\u094D\u092C\u0928\u094D\u0927\u093E\u0926\u094D\u0935\u093E\u0938\u0928\u093E\u0930\u0942\u092A\u0948\u0903 \u0936\u0941\u092D\u093E\u0936\u0941\u092D\u0948\u0930\u094D\u0928\u093F\u092C\u0926\u094D\u0927\u0903 \u0938\u0928\u094D \u092F\u094B\u0928\u0947\u0930\u094D\u092F\u094B\u0928\u094D\u092F\u0928\u094D\u0924\u0930\u0902 \u092A\u094D\u0930\u0938\u0930\u0928\u094D &quot; - &quot;Tatsambandh\u0101dv\u0101san\u0101r\u016Bpai\u1E25 \u015Bubh\u0101\u015Bubhairnibaddha\u1E25 san yoneryonyantara\u1E41 prasaran&quot; - &quot;\u0418\u0437-\u0437\u0430 [\u0441\u0432\u043E\u0435\u0439] \u0441\u0432\u044F\u0437\u0438 \u0441 \u044D\u0442\u0438\u043C [\u0442\u043E\u043D\u043A\u0438\u043C \u0442\u0435\u043B\u043E\u043C, \u0438\u043B\u0438 purya\u1E63\u1E6Daka], \u043E\u043D \u043F\u0440\u043E\u0434\u043E\u043B\u0436\u0430\u0435\u0442 \u0431\u044B\u0442\u044C \u0441\u0432\u044F\u0437\u0430\u043D \u0445\u043E\u0440\u043E\u0448\u0438\u043C\u0438 \u0438 \u043F\u043B\u043E\u0445\u0438\u043C\u0438 v\u0101san\u0101-s, \u0438\u043B\u0438 \u0442\u0435\u043D\u0434\u0435\u043D\u0446\u0438\u044F\u043C\u0438 [\u0432 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442\u0435 \u0434\u043E\u0431\u0440\u044B\u0445 \u0438 \u043F\u043B\u043E\u0445\u0438\u0445 \u0434\u0435\u044F\u043D\u0438\u0439, \u0438 \u0441\u043B\u0435\u0434\u043E\u0432\u0430\u0442\u0435\u043B\u044C\u043D\u043E,] \u043F\u0435\u0440\u0435\u0445\u043E\u0434\u0438\u0442 \u043E\u0442 \u043E\u0434\u043D\u043E\u0439 \u0444\u043E\u0440\u043C\u044B \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E\u0432\u0430\u043D\u0438\u044F \u043A \u0434\u0440\u0443\u0433\u043E\u0439&quot;. \u0422\u0435\u043F\u0435\u0440\u044C \u0432\u0441\u0435 \u044F\u0441\u043D\u043E, \u0442\u0430\u043A \u0432\u0435\u0434\u044C?</p></li></ol><p>:::</p><div class="stanza"><a href="#s3.11" id="s3.11" class="num">3.11</a><div class="sans"><p>\u0907\u0924\u094D\u0925\u092E\u0928\u094D\u0924\u0930\u093E\u0924\u094D\u092E\u0930\u0919\u094D\u0917\u0947 \u0928\u0943\u0924\u094D\u092F\u0924\u094B\u093D\u0938\u094D\u092F\u2014</p><blockquote><p><strong>\u092A\u094D\u0930\u0947\u0915\u094D\u0937\u0915\u093E\u0923\u0940\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u093E\u0923\u093F\u0965\u0967\u0967\u0965</strong></p></blockquote><p>\u092F\u094B\u0917\u093F\u0928\u0936\u094D\u091A\u0915\u094D\u0937\u0941\u0930\u093E\u0926\u0940\u0928\u0940\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u093E\u0923\u093F \u0939\u093F \u0938\u0902\u0938\u093E\u0930\u0928\u093E\u091F\u094D\u092F\u092A\u094D\u0930\u0915\u091F\u0928\u092A\u094D\u0930\u092E\u094B\u0926\u0928\u093F\u0930\u094D\u092D\u0930\u0902 \u0938\u094D\u0935\u0938\u094D\u0935\u0930\u0942\u092A\u092E\u0928\u094D\u0924\u0930\u094D\u092E\u0941\u0916\u0924\u092F\u093E \u0938\u093E\u0915\u094D\u0937\u093E\u0924\u094D\u0915\u0941\u0930\u094D\u0935\u0928\u094D\u0924\u093F \u0924\u0924\u094D\u092A\u094D\u0930\u092F\u094B\u0917\u092A\u094D\u0930\u0930\u0942\u0922\u094D\u092F\u093E \u0935\u093F\u0917\u0932\u093F\u0924\u0935\u093F\u092D\u093E\u0917\u093E\u0902 \u091A\u092E\u0924\u094D\u0915\u093E\u0930\u0930\u0938\u0938\u092E\u094D\u092A\u0942\u0930\u094D\u0923\u0924\u093E\u092E\u093E\u092A\u093E\u0926\u092F\u0928\u094D\u0924\u093F\u0964 \u092F\u091A\u094D\u091B\u094D\u0930\u0941\u0924\u093F\u0903</p><blockquote><p>\u0915\u0936\u094D\u091A\u093F\u0926\u094D\u0927\u0940\u0930\u0903 \u092A\u094D\u0930\u0924\u094D\u092F\u0917\u093E\u0924\u094D\u092E\u093E\u0928\u092E\u0948\u0915\u094D\u0937\u0926\u093E\u0935\u0943\u0924\u094D\u0924\u091A\u0915\u094D\u0937\u0941\u0930\u092E\u0943\u0924\u0924\u094D\u0935\u092E\u0936\u094D\u0928\u0928\u094D (...\u0907\u091A\u094D\u091B\u0928\u094D)\u0965<br> (\u0915\u0920\u094B\u092A\u0928\u093F\u0937\u0926\u093F \u0905\u0966 \u0968\u0964 \u0935\u0966 \u0967\u0964 \u092E\u0902\u0966 \u0967)</p></blockquote><p>\u0907\u0924\u093F\u0965\u0967\u0967\u0965</p></div><hr><div class="trans"><p>Itthamantar\u0101tmara\u1E45ge n\u1E5Btyato&#39;sya\u2014</p><blockquote><p><strong>Prek\u1E63ak\u0101\u1E47\u012Bndriy\u0101\u1E47i||11||</strong></p></blockquote><p>Yogina\u015Bcak\u1E63ur\u0101d\u012Bn\u012Bndriy\u0101\u1E47i hi sa\u1E41s\u0101ran\u0101\u1E6Dyapraka\u1E6Danapramodanirbhara\u1E41 svasvar\u016Bpamantarmukhatay\u0101 s\u0101k\u1E63\u0101tkurvanti tatprayogaprar\u016B\u1E0Dhy\u0101 vigalitavibh\u0101g\u0101\u1E41 camatk\u0101rarasasamp\u016Br\u1E47at\u0101m\u0101p\u0101dayanti| Yacchruti\u1E25</p><blockquote><p>Ka\u015Bciddh\u012Bra\u1E25 pratyag\u0101tm\u0101namaik\u1E63ad\u0101v\u1E5Bttacak\u1E63uram\u1E5Btatvama\u015Bnan (...icchan)||<br> (Ka\u1E6Dhopani\u1E63adi a. 2 | v. 1 | ma\u1E41. 1)</p></blockquote><p>iti||11||</p></div><hr><p>\u0422\u0430\u043A\u0438\u043C \u043E\u0431\u0440\u0430\u0437\u043E\u043C <em>(ittham)</em>, \u0443 \u0442\u043E\u0433\u043E <em>(asya)</em>, \u043A\u0442\u043E \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u0435\u0442 \u0438 \u0442\u0430\u043D\u0446\u0443\u0435\u0442 <em>(n\u1E5Btyata\u1E25)</em> \u043D\u0430 \u0441\u0446\u0435\u043D\u0435 <em>(ra\u1E45ge)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435\u0433\u043E <em>(antar)</em> \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u0438\u043B\u0438 \u0434\u0443\u0448\u0438 <em>(\u0101tma)</em>\u2014</p><blockquote><p><strong>\u0427\u0443\u0432\u0441\u0442\u0432\u0430 [\u044D\u0442\u043E\u0433\u043E Nartaka, \u0438\u043B\u0438 \u0442\u0430\u043D\u0446\u0443\u044E\u0449\u0435\u0433\u043E \u0430\u043A\u0442\u0435\u0440\u0430] <em>(indriy\u0101\u1E47i)</em> [\u044F\u0432\u043B\u044F\u044E\u0442\u0441\u044F] \u0437\u0440\u0438\u0442\u0435\u043B\u044F\u043C\u0438 [\u0435\u0433\u043E \u0438\u0433\u0440\u044B] <em>(prek\u1E63ak\u0101\u1E47i)</em>||11||</strong></p></blockquote><p>\u0427\u0443\u0432\u0441\u0442\u0432\u0430 <em>(indriy\u0101\u1E47i)</em> Yog\u012B <em>(yogina\u1E25)</em> \u2014\u0441\u043F\u043E\u0441\u043E\u0431\u043D\u043E\u0441\u0442\u044C \u0432\u0438\u0434\u0435\u0442\u044C <em>(cak\u1E63us)</em>, \u0438 \u0442.\u0434. <em>(\u0101d\u012Bni)</em>\u2014\u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi)</em>, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u044E\u0442 <em>(s\u0101k\u1E63\u0101t-kurvanti)</em> \u0432\u043D\u0443\u0442\u0440\u0435\u043D\u043D\u0435 <em>(antar-mukhatay\u0101)</em> \u0438\u0445 \u0441\u043E\u0431\u0441\u0442\u0432\u0435\u043D\u043D\u0443\u044E <em>(sva)</em> \u0441\u0443\u0449\u043D\u043E\u0441\u0442\u043D\u0443\u044E \u043F\u0440\u0438\u0440\u043E\u0434\u0443 <em>(sva-r\u016Bpam)</em>, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u043D\u0430\u043F\u043E\u043B\u043D\u0435\u043D\u0430 <em>(nirbharam)</em> \u0431\u0435\u0437\u043C\u0435\u0440\u043D\u044B\u043C \u043D\u0430\u0441\u043B\u0430\u0436\u0434\u0435\u043D\u0438\u0435\u043C <em>(pramoda)</em> \u043F\u0440\u0438 \u043F\u0440\u043E\u044F\u0432\u043B\u0435\u043D\u0438\u0438 <em>(praka\u1E6Dana)</em> \u0442\u0430\u043D\u0446\u0435\u0432\u0430\u043B\u044C\u043D\u043E\u0439 \u0434\u0440\u0430\u043C\u044B <em>(n\u0101\u1E6Dya)</em>, [\u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u043E\u0439] Sa\u1E41s\u0101ra --\u0442.\u0435. \u0422\u0440\u0430\u043D\u0441\u043C\u0438\u0433\u0440\u0430\u0446\u0438\u0435\u0439-- <em>(sa\u1E41s\u0101ra)</em>. \u0411\u043B\u0430\u0433\u043E\u0434\u0430\u0440\u044F \u0440\u0430\u0437\u0432\u0438\u0442\u0438\u044E <em>(prar\u016B\u1E0Dhy\u0101)</em> \u0441\u043F\u0435\u043A\u0442\u0430\u043A\u043B\u044F <em>(prayoga)</em> \u044D\u0442\u043E\u0439 [\u0442\u0430\u043D\u0446\u0435\u0432\u0430\u043B\u044C\u043D\u043E\u0439 \u0434\u0440\u0430\u043C\u044B] <em>(tad)</em>, \u043E\u043D\u0438 \u043F\u043E\u0431\u0443\u0436\u0434\u0430\u044E\u0442 [Yog\u012B] \u0432\u043E\u0439\u0442\u0438 <em>(\u0101p\u0101dayanti)</em> \u0432 \u043F\u043E\u043B\u043D\u043E\u0442\u0443 <em>(samp\u016Br\u1E47at\u0101m)</em> \u0432\u043A\u0443\u0441\u0430 <em>(rasa)</em> Camatk\u0101ra <em>(camatk\u0101ra)</em><sup>1</sup>, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0439 --\u0442.\u0435. \u0432 \u043F\u043E\u043B\u043D\u043E\u0442\u0435-- \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F \u0438 \u0434\u0432\u043E\u0439\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0441\u0442\u044C \u0438\u0441\u0447\u0435\u0437\u0430\u044E\u0442 <em>(vigalita-vibh\u0101g\u0101m)</em>|</p><p>\u041A\u0430\u043A [\u0433\u043E\u0432\u043E\u0440\u044F\u0442] Veda-s <em>(yad \u015Bruti\u1E25)</em>:</p><blockquote><p>&quot;[\u041E\u0434\u043D\u0430\u043A\u043E,] \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 <em>(ka\u015Bcid)</em> \u043C\u0443\u0434\u0440\u044B\u0435 \u043B\u044E\u0434\u0438 <em>(dh\u012Bra\u1E25)</em>, \u043F\u043E\u043B\u0443\u0447\u0438\u0432\u0448\u0438\u0435 <em>(a\u015Bnan)</em> \u2014\u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0435 <em>(icchan)</em><sup>2</sup>\u2014 \u0431\u0435\u0441\u0441\u043C\u0435\u0440\u0442\u0438\u0435 <em>(am\u1E5Btatvam)</em> \u0441 \u043F\u043E\u0432\u0435\u0440\u043D\u0443\u0442\u044B\u043C\u0438 \u043D\u0430\u0437\u0430\u0434 \u0433\u043B\u0430\u0437\u0430\u043C\u0438 <em>(\u0101v\u1E5Btta-cak\u1E63us)</em> --\u0442.\u0435. \u0438\u043D\u0442\u0440\u043E\u0441\u043F\u0435\u043A\u0442\u0438\u0432\u043D\u043E--, \u0441\u043E\u0437\u0435\u0440\u0446\u0430\u043B\u0438 <em>(aik\u1E63at)</em> \u0421\u0430\u043C\u043E\u0441\u0442\u044C <em>(\u0101tm\u0101nam)</em> \u0432\u043D\u0443\u0442\u0440\u0438 <em>(pratyak... iti)</em>&quot;||<br> [\u0421\u043C. Ka\u1E6Dhopani\u1E63ad II, 1, 1]</p></blockquote><p>||11||</p><hr><ol><li><p>Camatk\u0101ra \u0431\u0443\u043A\u0432\u0430\u043B\u044C\u043D\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0438\u0437\u0443\u043C\u043B\u0435\u043D\u0438\u0435, \u0443\u0434\u0438\u0432\u043B\u0435\u043D\u0438\u0435&quot;, \u043D\u043E \u0432 \u0430\u0440\u0442\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0439 \u0441\u0440\u0435\u0434\u0435 \u044D\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0432\u043E\u0441\u0442\u043E\u0440\u0433 \u0430\u0440\u0442\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u0442\u0432\u0430&quot;, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0432 \u0422\u0440\u0438\u043A\u0435 \u044D\u0442\u043E \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F&quot;. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u044D\u0442\u043E\u0442 \u0442\u0435\u0440\u043C\u0438\u043D \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043E\u0434\u043D\u0438\u043C \u0438\u0437 \u0442\u0435\u0445 \u0441\u043B\u043E\u0432, \u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0432\u044B \u043D\u0435 \u043C\u043E\u0436\u0435\u0442\u0435 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u0438\u0442\u044C \u0442\u043E\u0447\u043D\u043E \u0432\u0441\u0435 \u0432\u0440\u0435\u043C\u044F, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 \u0432\u0430\u0440\u044C\u0438\u0440\u0443\u0435\u0442\u0441\u044F \u0432 \u0437\u0430\u0432\u0438\u0441\u0438\u043C\u043E\u0441\u0442\u0438 \u043E\u0442 \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0430. \u0412 \u044D\u0442\u043E\u043C \u0441\u043B\u0443\u0447\u0430\u0435, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043F\u0440\u0435\u043F\u043E\u0434\u0430\u0435\u0442\u0441\u044F \u0422\u0440\u0438\u043A\u0430, \u0432\u044B \u043C\u043E\u0433\u043B\u0438 \u0431\u044B \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u043A\u0430\u043A &quot;\u0431\u043B\u0430\u0436\u0435\u043D\u0441\u0442\u0432\u043E \u0432\u044B\u0441\u0448\u0435\u0433\u043E \u042F-\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F&quot;, \u043D\u043E \u0432 \u0442\u043E \u0436\u0435 \u0432\u0440\u0435\u043C\u044F, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u0441\u044F \u043E \u0442\u0430\u043D\u0446\u0435\u0432\u0430\u043B\u044C\u043D\u043E\u0439 \u0434\u0440\u0430\u043C\u0435, \u0432\u044B \u0442\u0430\u043A\u0436\u0435 \u043C\u043E\u0436\u0435\u0442\u0435 \u0441\u0447\u0438\u0442\u0430\u0442\u044C \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u0432\u0435\u0440\u043D\u044B\u043C \u043F\u0435\u0440\u0435\u0432\u043E\u0434 &quot;\u0432\u043E\u0441\u0442\u043E\u0440\u0433 \u0430\u0440\u0442\u0438\u0441\u0442\u0438\u0447\u0435\u0441\u043A\u043E\u0433\u043E \u043C\u0430\u0441\u0442\u0435\u0440\u0441\u0442\u0432\u0430&quot;. \u0412\u043A\u043B\u044E\u0447\u0435\u043D\u0438\u0435 \u043E\u0431\u043E\u0438\u0445 \u043F\u0435\u0440\u0435\u0432\u043E\u0434\u043E\u0432 \u0432 \u0442\u0435\u043A\u0441\u0442 \u0431\u044B\u043B\u043E \u043D\u0435\u0443\u0434\u043E\u0431\u043D\u044B\u043C. \u0412\u043E\u0442 \u043F\u043E\u0447\u0435\u043C\u0443 \u044F \u043E\u0441\u0442\u0430\u0432\u0438\u043B Camatk\u0101ra \u043A\u0430\u043A \u0442\u0430\u043A\u043E\u0432\u0443\u044E. \u0418\u043D\u043E\u0433\u0434\u0430 \u043B\u044E\u0434\u0438 \u0436\u0430\u043B\u0443\u044E\u0442\u0441\u044F \u043D\u0430 \u044D\u0442\u0438 &quot;\u043D\u0430\u0437\u043E\u0439\u043B\u0438\u0432\u044B\u0435&quot; (\u0445\u0430-\u0445\u0430!) \u0441\u0430\u043D\u043A\u0440\u0438\u0442\u0441\u043A\u0438\u0435 \u0442\u0435\u0440\u043C\u0438\u043D\u044B \u0432 \u0441\u0435\u0440\u0435\u0434\u0438\u043D\u0435 \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u0438\u0439 \u043D\u0430 \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u043E\u043C, \u0438\u0441\u043F\u0430\u043D\u0441\u043A\u043E\u043C, \u043F\u043E\u0440\u0442\u0443\u0433\u0430\u043B\u044C\u0441\u043A\u043E\u043C \u0438 \u043F\u0440. \u041E\u043D\u0438 \u0436\u0430\u043B\u0443\u044E\u0442\u0441\u044F, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D\u0438 \u043D\u0435 \u043F\u043E\u043D\u0438\u043C\u0430\u044E\u0442, \u0447\u0442\u043E \u0442\u043E\u0447\u043D\u044B\u0439 \u043F\u0435\u0440\u0435\u0432\u043E\u0434 \u0431\u044B\u0432\u0430\u0435\u0442 \u0438\u043D\u043E\u0433\u0434\u0430 \u043D\u0430\u0441\u0442\u043E\u043B\u044C\u043A\u043E \u0434\u043B\u0438\u043D\u043D\u044B\u043C \u0438/\u0438\u043B\u0438 \u0440\u0430\u0437\u043D\u044B\u043C, \u0447\u0442\u043E \u043F\u0440\u043E\u0441\u0442\u043E \u043D\u0435 \u0443\u0434\u043E\u0431\u043D\u043E \u0432\u043A\u043B\u044E\u0447\u0430\u0442\u044C \u0435\u0433\u043E \u0432 \u0441\u0430\u043C\u043E \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u0438\u0435. \u0412\u044B \u0437\u043D\u0430\u0435\u0442\u0435, \u0447\u0442\u043E \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u0438\u0439, \u0438\u0441\u043F\u0430\u043D\u0441\u043A\u0438\u0439, \u043F\u043E\u0440\u0442\u0443\u0433\u0430\u043B\u044C\u0441\u043A\u0438\u0439 \u0438 \u043F\u0440\u043E\u0447\u0438\u0435 \u043E\u0431\u0449\u0435\u0443\u043F\u043E\u0442\u0440\u0435\u0431\u0438\u0442\u0435\u043B\u044C\u043D\u044B\u0435 \u044F\u0437\u044B\u043A\u0438 \u043D\u0430\u0441\u0442\u043E\u043B\u044C\u043A\u043E \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u044B \u0438 \u0434\u0432\u0443\u0441\u043C\u044B\u0441\u043B\u0435\u043D\u043D\u044B, \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A \u0441\u0430\u043D\u0441\u043A\u0440\u0438\u0442 \u2014 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u043E \u043D\u0435\u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u044B\u0439 \u0438 \u0442\u043E\u0447\u043D\u044B\u0439.</p></li><li><p>\u0414\u0432\u0430 \u0432\u043E\u0437\u043C\u043E\u0436\u043D\u044B\u0445 \u043F\u0440\u043E\u0447\u0442\u0435\u043D\u0438\u044F: &quot;\u0905\u0936\u094D\u0928\u0928\u094D &quot; - &quot;a\u015Bnan&quot; - &quot;\u043F\u043E\u043B\u0443\u0447\u0438\u0432\u0448\u0438\u0439/\u0434\u043E\u0431\u0438\u0432\u0448\u0438\u0439\u0441\u044F&quot; \u0438\u043B\u0438 &quot;\u0907\u091A\u094D\u091B\u0928\u094D &quot; - &quot;icchan&quot; - &quot;\u0436\u0435\u043B\u0430\u044E\u0449\u0438\u0439/\u043F\u0440\u043E\u0441\u044F\u0449\u0438\u0439&quot;. \u042D\u0442\u043E \u043E\u0431\u044B\u0447\u043D\u043E, \u043A\u043E\u0433\u0434\u0430 \u0432\u044B \u043C\u043E\u0436\u0435\u0442\u0435 \u043E\u0431\u043D\u0430\u0440\u0443\u0436\u0438\u0442\u044C \u041F\u0438\u0441\u0430\u043D\u0438\u044F \u0441 \u043C\u043D\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u044B\u043C \u043F\u0440\u043E\u0447\u0442\u0435\u043D\u0438\u0435\u043C \u0432 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0445 \u0447\u0430\u0441\u0442\u044F\u0445 \u0442\u0435\u043A\u0441\u0442\u0430. \u041F\u043E\u044D\u0442\u043E\u043C\u0443 \u0437\u0434\u0435\u0441\u044C \u044D\u0442\u043E \u043D\u0435 \u0443\u0434\u0438\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E.</p></li></ol></div>',16),p=[o];function n(s,i,u,k,d,c){return m(),e("div",null,p)}var q=a(r,[["render",n]]);export{y as __pageData,q as default};
